INSERT INTO "public"."metadata_data_system_method" ("id", "method_code", "method_name", "method_type", "method_url", "method_description", "is_enabled", "request_method", "deleted", "creator", "create_time", "updater", "update_time") VALUES
(1, 'CREATE_SINGLE', '新增单条数据', 'CREATE', '/metadata/data-method/insert', '数据模型的新增服务，该服务会在业务对象被判断为新增的时候被调用', 1, 'POST', 0, 1, '2025-08-06 14:22:32.98068', 1, '2025-08-06 14:22:32.98068'),
(2, 'UPDATE_SINGLE', '更新单条数据', 'UPDATE', '/metadata/data-method/update', '数据模型的更新服务，通过主键更新模型已存在的数据', 1, 'POST', 0, 1, '2025-08-06 14:22:32.98068', 1, '2025-08-06 14:22:32.98068'),
(3, 'DELETE_SINGLE', '删除单条数据', 'DELETE', '/metadata/data-method/delete', '数据模型的删除单条记录的服务，通过主键删除目标模型中符合条件的数据', 1, 'POST', 0, 1, '2025-08-06 14:22:32.98068', 1, '2025-08-06 14:22:32.98068'),
(4, 'GET_BY_ID', '根据id查询数据详情', 'READ', '/metadata/data-method/data', '通过主键获取单条数据使用的服务，用来接收一条结果集', 1, 'POST', 0, 1, '2025-08-06 14:22:32.98068', 1, '2025-08-06 14:22:32.98068'),
(5, 'GET_PAGE_LIST', '分页查询数据列表', 'READ', '/metadata/data-method/data/page', '通过查询条件获取多条数据使用的服务，用来接收多条结果集', 1, 'POST', 0, 1, '2025-08-06 14:22:32.98068', 1, '2025-08-06 14:22:32.98068'),
(6, 'GET_GROUP_LIST', '分组查询数据', 'READ', '/metadata/data-method', '看板视图下通过指定字段进行分组，分别获取多条数据使用的服务（例如该分组下的前N条）', 1, 'POST', 0, 1, '2025-08-06 14:22:32.98068', 1, '2025-08-06 14:22:32.98068'),
(7, 'GET_TREE_LIST', '树状视图数据查询', 'READ', '/metadata/data-method', '用于支持树状结构展示的数据查询服务，通过指定父子级字段递归查询出具有层级关系的数据集合，适用于树形视图、组织架构、目录结构等场景', 1, 'POST', 0, 1, '2025-08-06 14:22:32.98068', 1, '2025-08-06 14:22:32.98068'),
(8, 'CREATE_BATCH', '批量新增', 'BATCH', '/metadata/data-method', '数据模型的批量新增服务，该服务会在接收到多条新增数据请求时被调用，支持一次插入多条记录', 1, 'POST', 0, 1, '2025-08-06 14:22:32.98068', 1, '2025-08-06 14:22:32.98068'),
(9, 'UPDATE_BATCH', '批量更新', 'BATCH', '/metadata/data-method', '数据模型的批量更新服务，通过主键集合批量更新符合条件的多条记录，适用于批量修改、批量设置等业务场景', 1, 'POST', 0, 1, '2025-08-06 14:22:32.98068', 1, '2025-08-06 14:22:32.98068'),
(10, 'DELETE_BATCH', '批量删除', 'BATCH', '/metadata/data-method', '数据模型的批量删除服务，通过主键集合批量删除目标模型中符合条件的多条记录，常用于多选删除操作，需支持事务控制以保证数据完整性', 1, 'POST', 0, 1, '2025-08-06 14:22:32.98068', 1, '2025-08-06 14:22:32.98068'),
(11, 'DRAFT_SAVE_QUERY', '草稿保存与查询服务', 'DRAFT', '/metadata/data-method', '用于支持草稿状态的数据保存与查询服务，允许用户在未正式发布前暂存数据（数据只有该用户能看到），并支持后续继续编辑或提交，适用于长表单填写的场景', 1, 'POST', 0, 1, '2025-08-06 14:22:32.98068', 1, '2025-08-06 14:22:32.98068'),
(12, 'IMPORT_DATA', '数据导入服务', 'BATCH', '/metadata/data-method', '用于支持数据导入功能的服务，支持从文件或其他数据源批量导入数据到指定实体，适用于数据迁移、批量初始化等场景', 1, 'POST', 0, 1, '2025-08-06 14:22:32.98068', 1, '2025-08-06 14:22:32.98068');
